  canal = 'Google Ads';
  canalScore = 45;
}
else if (isMetaAds) {
  canal = 'Meta Ads';
  canalScore = 30;
}
else if (isSeo) {
  canal = 'SEO';
  canalScore = 50;
}
else if (isLinkBio) {
  canal = 'Link da Bio';
  canalScore = 35;
}



const faturamentoMap = {
  'Não tem faturamento': [10, 'Pequeno'],
  'Menos de R$1000': [10, 'Pequeno'],
