  'R$10.001 à R$20.000': [25, 'Médio'],
  'R$20.001 à R$30.000': [30, 'Médio'],
  'R$30.001 à R$50.000': [35, 'Médio'],
  'R$50.001 à R$100.000': [45, 'Grande'],
  'Acima de R$100.000': [50, 'MGP'],
};

const [faturamentoScore, porte] =
  faturamentoMap[faturamento] || [10, 'Pequeno'];



const score = canalScore + faturamentoScore;



let tier = '5';

if (score >= 85) tier = '1';
else if (score >= 70) tier = '2';
else if (score >= 55) tier = '3';
else if (score >= 40) tier = '4';




return [
  {
    json: {
      ...data,

      canal,
      porte,

      canalScore,
      faturamentoScore,

      score,
      tier
    }
  }
];

