const data = $input.first().json;

// Pegando os valores dos campos estruturados
const page = (data['Page URL'] || '').toLowerCase();
const utmSource = (data['utm_source'] || '').toLowerCase();
const utmMedium = (data['utm_medium'] || '').toLowerCase();
const utmCampaign = (data['utm_campaign'] || '').toLowerCase();
const utmTerm = (data['utm_term'] || '').toLowerCase();
const utmContent = (data['utm_content'] || '').toLowerCase();
const utmPlacement = (data['utm_placement'] || '').toLowerCase();
