else if (isSeo) canal = 'SEO';
else if (isLinkBio) canal = 'Link da Bio';

// ------------------------------
// 2) Detectar porte (agora com "Não sei")
// ------------------------------
const faturamentoMap = {
  'Não tem faturamento': ['Não tem'],
  'Não sei': ['Não sei'],
  'Menos de R$1000': ['Pequeno'],
  'R$1.001 à R$5.000': ['Pequeno'],
  'R$5.001 à R$10.000': ['Pequeno'],
  'R$10.001 à R$20.000': ['Médio'],
  'R$20.001 à R$30.000': ['Médio'],
  'R$30.001 à R$50.000': ['Médio'],
  'R$50.001 à R$100.000': ['Grande'],
  'Acima de R$100.000': ['Grande'],
};

