  ['Não tem', 'SEO'],
  ['Médio', 'SEO'],
  ['Grande', 'SEO'],
  ['Médio', 'Link da Bio'],
  ['Grande', 'Link da Bio'],
  ['Médio', 'Google Ads'],
  ['Grande', 'Google Ads'],
  ['Médio', 'Outros'],
  ['Grande', 'Outros'],
];

// Tier 2
const tier2 = [
  ['Pequeno', 'SEO'],
  ['Não tem', 'Link da Bio'],
  ['Pequeno', 'Link da Bio'],
  ['Grande', 'Meta Ads'],
  ['Não sei', 'Link da Bio'],
];

// Tier 3.1
const tier31 = [
  ['Não tem', 'Google Ads'],
  ['Pequeno', 'Google Ads'],
  ['Não sei', 'SEO'],
];

// Tier 3.2
const tier32 = [
  ['Pequeno', 'Outros'],
  ['Médio', 'Meta Ads'],
];

// Tier 4
const tier4 = [
  ['Não tem', 'Outros'],
  ['Não sei', 'Google Ads'],
  ['Não sei', 'Outros'],
];

// Tier 5 (Meta baixo ou Não sei + Meta)
const tier5 = [
  ['Não sei', 'Meta Ads'],
];

// Função de decisão
const findTier = () => {
  for (const [p, c] of tier1) if (match(p, c)) return '1';
  for (const [p, c] of tier2) if (match(p, c)) return '2';
  for (const [p, c] of tier31) if (match(p, c)) return '3.1';
  for (const [p, c] of tier32) if (match(p, c)) return '3.2';
  for (const [p, c] of tier4) if (match(p, c)) return '4';
  for (const [p, c] of tier5) if (match(p, c)) return '5';
  return '5';
};

const tier = findTier();

// ------------------------------
// 4) Retorno
// ------------------------------
return [
  {
    json: {
      canal,
      porte,
      tier,
      tier_modelo: 'combinação origem x porte (com Não sei)',
    }
  }
];

