		const [key, value] = pair.split('=');
		params[decodeURIComponent(key)] = decodeURIComponent(value || '');
	}

	return params;
}

const params = getParams(pageUrl);

if (!params) {
	return [{ json: body }];
}

function fillField(fieldName) {
	return body[fieldName] || params[fieldName] || "";
}

const output = {
	...body,

	// UTMs padrão
	utm_source: fillField('utm_source'),
	utm_medium: fillField('utm_medium'),
	utm_campaign: fillField('utm_campaign'),
	utm_content: fillField('utm_content'),
	utm_term: fillField('utm_term'),
	utm_placement: fillField('utm_placement'),

	// UTMs avançadas (Meta / Google)
	utm_id: fillField('utm_id'),
	utm_campaign_id: fillField('utm_campaign_id'),
	utm_adset_id: fillField('utm_adset_id'),
	utm_ad_id: fillField('utm_ad_id'),
	utm_source_platform: fillField('utm_source_platform'),
	utm_creative_format: fillField('utm_creative_format'),
	utm_marketing_tactic: fillField('utm_marketing_tactic'),

	// Click IDs
	gclid: fillField('gclid'),
	fbclid: fillField('fbclid'),
	fbc: fillField('fbc'),
};

return [{ json: output }];

const data = $input.first().json;

// Pegando os valores dos campos estruturados
const page = (data['Page URL'] || '').toLowerCase();
const utmSource = (data['utm_source'] || '').toLowerCase();
const utmMedium = (data['utm_medium'] || '').toLowerCase();
const utmCampaign = (data['utm_campaign'] || '').toLowerCase();
const utmTerm = (data['utm_term'] || '').toLowerCase();
const utmContent = (data['utm_content'] || '').toLowerCase();
const utmPlacement = (data['utm_placement'] || '').toLowerCase();
const origemCampanha = (data['Origem da Campanha'] || '').toLowerCase();
const faturamento = (data['Faturamento'] || '').trim();

// ------------------------------
// 1) Detectar canal
// ------------------------------
const isGoogleAds =
  utmSource === 'google' ||
  utmMedium === 'paidsearch' ||
  origemCampanha.includes('google pago') ||
  page.includes('lp-google') ||
  page.includes('lp-google-ads');

const isMetaAds =
  utmMedium === 'paid' ||
  origemCampanha.includes('meta ads') ||
  page.includes('lp-meta-ads') ||
  page.includes('lp-fb-ads'); 

const hasAnyUtm =
  utmMedium ||
  utmCampaign ||
  utmTerm ||
  utmContent ||
  utmPlacement;

const isSeo =
  (
    utmSource === 'www.google.com' ||
    utmSource === 'www.bing.com' ||
    utmSource === 'br.search.yahoo.com'
  ) && !hasAnyUtm;

const isLinkBio =
  utmSource.includes('rd_station_link_na_bio') ||
  utmSource.includes('cardapio-web-link-na-bio') ||
  utmSource.includes('linktree') ||
  page.includes('lp-instagram');

let canal = 'Outros';
if (isGoogleAds) canal = 'Google Ads';
else if (isMetaAds) canal = 'Meta Ads';
else if (isSeo) canal = 'SEO';
else if (isLinkBio) canal = 'Link da Bio';

// ------------------------------
// 2) Detectar porte (agora com "Não sei")
// ------------------------------
const faturamentoMap = {
  'Não tem faturamento': ['Não tem'],
  'Não sei': ['Não sei'],
  'Menos de R$1000': ['Pequeno'],
  'R$1.001 à R$5.000': ['Pequeno'],
  'R$5.001 à R$10.000': ['Pequeno'],
  'R$10.001 à R$20.000': ['Médio'],
  'R$20.001 à R$30.000': ['Médio'],
  'R$30.001 à R$50.000': ['Médio'],
  'R$50.001 à R$100.000': ['Grande'],
  'Acima de R$100.000': ['Grande'],
};

let porte = (faturamentoMap[faturamento]?.[0]) || 'Pequeno';

// ------------------------------
// 3) Tierização por combinação
// ------------------------------
const match = (p, c) => porte === p && canal === c;

// Tier 1
const tier1 = [
  ['Não tem', 'SEO'],
  ['Médio', 'SEO'],
  ['Grande', 'SEO'],
  ['Médio', 'Link da Bio'],
  ['Grande', 'Link da Bio'],
  ['Médio', 'Google Ads'],
  ['Grande', 'Google Ads'],
  ['Médio', 'Outros'],
  ['Grande', 'Outros'],
];

// Tier 2
const tier2 = [
  ['Pequeno', 'SEO'],
  ['Não tem', 'Link da Bio'],
  ['Pequeno', 'Link da Bio'],
  ['Grande', 'Meta Ads'],
  ['Não sei', 'Link da Bio'],
];

// Tier 3.1
const tier31 = [
  ['Não tem', 'Google Ads'],
  ['Pequeno', 'Google Ads'],
  ['Não sei', 'SEO'],
];

// Tier 3.2
const tier32 = [
  ['Pequeno', 'Outros'],
  ['Médio', 'Meta Ads'],
];

// Tier 4
const tier4 = [
  ['Não tem', 'Outros'],
  ['Não sei', 'Google Ads'],
  ['Não sei', 'Outros'],
];

// Tier 5 (Meta baixo ou Não sei + Meta)
const tier5 = [
  ['Não sei', 'Meta Ads'],
];

// Função de decisão
const findTier = () => {
  for (const [p, c] of tier1) if (match(p, c)) return '1';
  for (const [p, c] of tier2) if (match(p, c)) return '2';
  for (const [p, c] of tier31) if (match(p, c)) return '3.1';
  for (const [p, c] of tier32) if (match(p, c)) return '3.2';
  for (const [p, c] of tier4) if (match(p, c)) return '4';
  for (const [p, c] of tier5) if (match(p, c)) return '5';
  return '5';
};

const tier = findTier();

// ------------------------------
// 4) Retorno
// ------------------------------
return [
  {
    json: {
      canal,
      porte,
      tier,
      tier_modelo: 'combinação origem x porte (com Não sei)',
    }
  }
];

